-- 2. 예약 시간(Time) 14개 삽입

-- 3. 예약(Reservation) 삽입 (status: 'CONFIRMED' 사용)
-- [Theme 1: 폐병원 탈출]

-- [Theme 2: 비밀요원 Z]

-- [과거 데이터]

-- 4. 테마 슬롯(Theme_Slot) 동기화
-- 취소된 예약을 제외하고 활성화된 예약들을 슬롯에 반영합니다.
SELECT theme_id, date, time_id, TRUE
FROM reservation
WHERE status != 'CANCELLED';